mapper.insert:
/** UsptBsnsPlanProcessHistDao.insert */
		insert into uspt_bsns_plan_process_hist (
		 plan_process_hist_id
		,bsns_plan_doc_id
		,plan_presentn_sttus_cd
		,resn_cn
		,creator_id
		,created_dt
	) values (
		 #{planProcessHistId}
		,#{bsnsPlanDocId}
		,#{planPresentnSttusCd}
		,#{resnCn}
		,#{creatorId}
		,#{createdDt}
	)

mapper.update:
/** UsptBsnsPlanProcessHistDao.update */
update uspt_bsns_plan_process_hist
	 set  plan_presentn_sttus_cd    = #{planPresentnSttusCd}
		  ,resn_cn                   = #{resnCn}
where plan_process_hist_id = #{planProcessHistId}
   and bsns_plan_doc_id = #{bsnsPlanDocId}

mapper.delete:
/** UsptBsnsPlanDocDao.delete */
delete from uspt_bsns_plan_process_hist
        where plan_process_hist_id = #{planProcessHistId}

	       and bsns_plan_doc_id = #{bsnsPlanDocId}

mapper.select:
/** UsptBsnsPlanProcessHistDao.selectList */ select row_number() over (order by created_dt) as rn ,plan_process_hist_id ,bsns_plan_doc_id ,plan_presentn_sttus_cd ,fn_cmm_get_code_nm('PLAN_PRESENTN_STTUS', ubpph.plan_presentn_sttus_cd) as plan_presentn_sttus_nm /*사업계획제출상태명*/ ,resn_cn ,creator_id ,(select cm.member_nm from cmmt_member cm where cm.member_id = ubpph.creator_id ) as creatr_nm /*회원명(신청자명) */ ,created_dt from uspt_bsns_plan_process_hist ubpph where 1=1
and plan_process_hist_id = #{planProcessHistId}
and bsns_plan_doc_id = #{bsnsPlanDocId}
and planPresentnSttusCd = #{planPresentnSttusCd}
offset #{beginRowNum} - 1 limit #{itemsPerPage}

/** UsptBsnsPlanProcessHistDao.selectListCnt */
	select  count(1)
	from uspt_bsns_plan_process_hist
  where	1=1

	 and 	 plan_process_hist_id = #{planProcessHistId}


	 and 	 bsns_plan_doc_id = #{bsnsPlanDocId}


	 and 	 planPresentnSttusCd = #{planPresentnSttusCd}
